<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import PageHeader from '@/components/PageHeader.vue'
import type { ImportResult, Student } from '@/types'
import { createStudent, deleteStudent, getStudents, importStudents, provisionStudentAccounts, resetStudentPassword, type StudentCredential, updateStudent } from '@/api/students'
import { ElMessage, ElMessageBox, type UploadFile } from 'element-plus'

const loading=ref(false),dialog=ref(false),importDialog=ref(false),credentialsDialog=ref(false),rows=ref<Student[]>([]),total=ref(0),selectedFile=ref<File>(),importResult=ref<ImportResult>(),credentials=ref<StudentCredential[]>([])
const selectedRows=ref<Student[]>([]),batchDeleting=ref(false),provisioning=ref(false)
const query=reactive({current:1,size:10,keyword:'',status:''})
const form=reactive<Student>({student_id:0,student_no:'',student_name:'',college:'',major:'',class_name:''})
const importForm=reactive({batch_name:'',template_id:1})
const credentialText=computed(()=>credentials.value.map(item=>`${item.studentName}\t${item.studentNo}\t${item.initialPassword}`).join('\n'))
async function load(){loading.value=true;try{const p=await getStudents(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}
function reset(){query.keyword='';query.current=1;load()}
function open(row?:Student){Object.assign(form,row||{student_id:0,student_no:'',student_name:'',college:'',major:'',class_name:''});dialog.value=true}
async function save(){if(!form.student_no||!form.student_name)return ElMessage.warning('请填写学号和姓名');if(form.student_id)await updateStudent(form.student_id,form);else await createStudent(form);ElMessage.success('保存成功');dialog.value=false;load()}
async function remove(row:Student){await ElMessageBox.confirm(`确认删除学生“${row.student_name}”吗？`,'删除学生',{type:'warning'});await deleteStudent(row.student_id);ElMessage.success('删除成功');load()}
function handleSelectionChange(selection:Student[]){selectedRows.value=selection}
async function removeSelected(){if(!selectedRows.value.length)return ElMessage.warning('请先选择要删除的学生');await ElMessageBox.confirm(`确认删除选中的 ${selectedRows.value.length} 名学生吗？此操作不可恢复。`,'批量删除',{type:'warning'});batchDeleting.value=true;try{const results=await Promise.allSettled(selectedRows.value.map(row=>deleteStudent(row.student_id)));const successCount=results.filter(result=>result.status==='fulfilled').length;ElMessage.success(`批量删除完成：成功 ${successCount} 条`);selectedRows.value=[];await load()}finally{batchDeleting.value=false}}
async function provision(){if(!selectedRows.value.length)return ElMessage.warning('请先选择要开通账号的学生');provisioning.value=true;try{const result=await provisionStudentAccounts(selectedRows.value.map(row=>row.student_id));credentials.value=result.created;if(result.created.length){credentialsDialog.value=true;ElMessage.success(`已开通 ${result.created.length} 个学生账号`)}else ElMessage.warning('所选学生均已开通账号或存在用户名冲突')}finally{provisioning.value=false}}
async function resetPassword(row:Student){await ElMessageBox.confirm(`重置 ${row.student_name} 的密码后，该学生需要重新登录并修改密码。`,'重置学生密码',{type:'warning'});const credential=await resetStudentPassword(row.student_id);credentials.value=[credential];credentialsDialog.value=true}
const importLoading=ref(false)
function choose(file:UploadFile){selectedFile.value=file.raw}
async function upload(){if(importLoading.value||!selectedFile.value)return;importLoading.value=true;try{importResult.value=await importStudents(selectedFile.value,importForm.batch_name,importForm.template_id);ElMessage.success('导入完成');await load()}finally{importLoading.value=false}}
async function copyCredentials(){try{await navigator.clipboard.writeText(credentialText.value);ElMessage.success('初始密码已复制')}catch{ElMessage.info('请手动复制凭据')}}
onMounted(load)
</script>
<template><div><PageHeader title="学生管理" description="维护学生档案、导入名单并开通学生登录账号"><el-button @click="importDialog=true">Excel导入</el-button><el-button type="primary" @click="open()">新增学生</el-button></PageHeader><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="学号、姓名或班级" clearable style="width:260px" @keyup.enter="query.current=1;load()"/><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button><el-button type="success" plain :disabled="!selectedRows.length" :loading="provisioning" @click="provision">开通学生账号（{{selectedRows.length}}）</el-button><el-button type="danger" plain :disabled="!selectedRows.length" :loading="batchDeleting" @click="removeSelected">批量删除（{{selectedRows.length}}）</el-button></div><el-table v-loading="loading" :data="rows" @selection-change="handleSelectionChange" empty-text="暂无学生数据"><el-table-column type="selection" width="52"/><el-table-column prop="student_no" label="学号"/><el-table-column prop="student_name" label="姓名"/><el-table-column prop="college" label="学院"/><el-table-column prop="major" label="专业"/><el-table-column prop="class_name" label="班级"/><el-table-column label="操作" width="210"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="warning" @click="resetPassword(s.row)">重置密码</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" :page-sizes="[10,20,50]" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-dialog v-model="dialog" :title="form.student_id?'编辑学生':'新增学生'" width="560"><el-form label-position="top"><div class="form-grid"><el-form-item label="学号" required><el-input v-model="form.student_no"/></el-form-item><el-form-item label="姓名" required><el-input v-model="form.student_name"/></el-form-item><el-form-item label="学院"><el-input v-model="form.college"/></el-form-item><el-form-item label="专业"><el-input v-model="form.major"/></el-form-item></div><el-form-item label="班级"><el-input v-model="form.class_name"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-dialog v-model="importDialog" title="导入学生名单" width="620"><el-form label-position="top"><div class="form-grid"><el-form-item label="批次名称"><el-input v-model="importForm.batch_name"/></el-form-item><el-form-item label="模板ID"><el-input-number v-model="importForm.template_id" :min="1"/></el-form-item></div></el-form><el-upload drag :auto-upload="false" :limit="1" accept=".xlsx,.xls" @change="choose"><div class="upload-title">拖入Excel文件或点击选择</div></el-upload><el-alert v-if="importResult" class="import-result" :title="`成功 ${importResult.success_count} 条，失败 ${importResult.failed_count} 条`" :description="importResult.failures.map(x=>`第${x.row}行：${x.reason}`).join('；')||'全部导入成功'" :type="importResult.failed_count?'warning':'success'" show-icon/><template #footer><el-button :disabled="importLoading" @click="importDialog=false">关闭</el-button><el-button type="primary" :loading="importLoading" :disabled="!selectedFile" @click="upload">{{importLoading?'正在导入':'开始导入'}}</el-button></template></el-dialog><el-dialog v-model="credentialsDialog" title="学生初始登录凭据" width="620" :close-on-click-modal="false"><el-alert title="初始密码只在本次操作显示，请立即复制并通过班级渠道发给对应学生。学生首次登录后必须修改密码。" type="warning" :closable="false"/><el-input class="credentials" :model-value="credentialText" type="textarea" :rows="Math.min(Math.max(credentials.length+1,4),12)" readonly/><template #footer><el-button @click="credentialsDialog=false">已记录，关闭</el-button><el-button type="primary" @click="copyCredentials">复制凭据</el-button></template></el-dialog></div></template>
<style scoped>.credentials{margin-top:16px;font-family:Consolas,monospace}</style>
